// Renderiza o mapa base, a camada de polígonos de solo, o popup e a legenda.

import { useCallback, useMemo, useState, type FocusEvent, type MouseEvent } from "react";
import {
  Map,
  Source,
  Layer,
  Popup,
  Marker,
  type MapLayerMouseEvent,
} from "react-map-gl/maplibre";
import "maplibre-gl/dist/maplibre-gl.css";
import "./map-manager.css";
import {
  SoilFeatureCollection,
  SoilProperties,
  type ActiveProject,
} from "./types";
import { SOIL_CLASSES, OUTROS, getSoilClass, type SoilClass } from "./soilClasses";

// Expressão MapLibre que pinta cada polígono conforme a classe do solo.
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const COLOR_MATCH: any = [
  "match",
  ["get", "soilClass"],
  ...SOIL_CLASSES.flatMap((c) => [c.code, c.color]),
  OUTROS.color,
];

export interface MapViewProps {
  /** GeoJSON com as features de solo já anotadas com `soilClass`. */
  data: SoilFeatureCollection | null;
  /** Conjunto de códigos de classe atualmente visíveis. */
  activeFilters: Set<string>;
  /** Projetos em execução plotados como pins sobre o mapa. */
  projects?: ActiveProject[];
  /** Estilo de mapa-base do MapLibre. */
  mapStyle?: string;
  /** View inicial — default centralizado no Brasil. */
  initialViewState?: { longitude: number; latitude: number; zoom: number };
}

interface Selection {
  longitude: number;
  latitude: number;
  properties: SoilProperties;
}

interface LegendTooltipState {
  cls: SoilClass;
  /** Coordenadas (viewport) do canto inferior-direito do item — âncora do tooltip. */
  anchorRight: number;
  anchorTop: number;
}

const DEFAULT_VIEW = { longitude: -53, latitude: -14, zoom: 3.6 };
const DEFAULT_MAP_STYLE = "https://tiles.openfreemap.org/styles/liberty";

export default function MapView({
  data,
  activeFilters,
  projects,
  mapStyle = DEFAULT_MAP_STYLE,
  initialViewState = DEFAULT_VIEW,
}: MapViewProps) {
  const [selected, setSelected] = useState<Selection | null>(null);
  const [tooltip, setTooltip] = useState<LegendTooltipState | null>(null);
  const [hoveredProject, setHoveredProject] = useState<ActiveProject | null>(null);

  const showTooltip = useCallback(
    (cls: SoilClass, rect: DOMRect) => {
      setTooltip({ cls, anchorRight: rect.right, anchorTop: rect.top });
    },
    []
  );
  const hideTooltip = useCallback(() => setTooltip(null), []);

  // Filtro nativo do MapLibre: mostra só features cujo soilClass está ativo.
  const filterExpr = useMemo(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (): any => [
      "in",
      ["get", "soilClass"],
      ["literal", Array.from(activeFilters)],
    ],
    [activeFilters]
  );

  const handleClick = (e: MapLayerMouseEvent) => {
    const feat = e.features?.[0];
    if (!feat) {
      setSelected(null);
      return;
    }
    setSelected({
      longitude: e.lngLat.lng,
      latitude: e.lngLat.lat,
      properties: feat.properties as SoilProperties,
    });
  };

  return (
    <div className="map-container">
      <Map
        initialViewState={initialViewState}
        style={{ width: "100%", height: "100%" }}
        mapStyle={mapStyle}
        interactiveLayerIds={data ? ["soil-fill"] : []}
        onClick={handleClick}
      >
        {data && (
          <Source id="solos" type="geojson" data={data}>
            <Layer
              id="soil-fill"
              type="fill"
              filter={filterExpr}
              paint={{
                "fill-color": COLOR_MATCH,
                "fill-opacity": 0.55,
              }}
            />
            <Layer
              id="soil-outline"
              type="line"
              filter={filterExpr}
              paint={{
                "line-color": "#1a1a2e",
                "line-width": 0.3,
                "line-opacity": 0.35,
              }}
            />
          </Source>
        )}

        {selected && (
          <Popup
            longitude={selected.longitude}
            latitude={selected.latitude}
            onClose={() => setSelected(null)}
            closeOnClick={false}
            anchor="bottom"
            offset={8}
            maxWidth="320px"
          >
            <SoilPopupContent properties={selected.properties} />
          </Popup>
        )}

        {projects?.map((project) => (
          <Marker
            key={`${project.lat}-${project.lng}-${project.title}`}
            longitude={project.lng}
            latitude={project.lat}
            anchor="bottom"
          >
            <button
              type="button"
              className="project-pin"
              onMouseEnter={() => setHoveredProject(project)}
              onMouseLeave={() => setHoveredProject(null)}
              onFocus={() => setHoveredProject(project)}
              onBlur={() => setHoveredProject(null)}
              aria-label={project.title}
            >
              <svg
                width="26"
                height="34"
                viewBox="0 0 26 34"
                fill="none"
                aria-hidden="true"
              >
                <path
                  d="M13 0C5.82 0 0 5.82 0 13c0 9.75 13 21 13 21s13-11.25 13-21C26 5.82 20.18 0 13 0z"
                  fill="#a8521f"
                />
                <circle cx="13" cy="13" r="5" fill="#fff" />
              </svg>
            </button>
          </Marker>
        ))}

        {hoveredProject && (
          <Popup
            longitude={hoveredProject.lng}
            latitude={hoveredProject.lat}
            onClose={() => setHoveredProject(null)}
            closeOnClick={false}
            closeButton={false}
            anchor="bottom"
            offset={36}
            maxWidth="320px"
            className="project-popup-wrapper"
          >
            <ProjectPopupContent project={hoveredProject} />
          </Popup>
        )}
      </Map>

      {!data && <div className="map-overlay">Carregando solos…</div>}

      <div className="legend">
        <h3>Legenda</h3>
        <div className="legend-scroll">
          {SOIL_CLASSES.filter((c) => activeFilters.has(c.code)).map((c) => (
            <LegendItem
              key={c.code}
              cls={c}
              onShow={showTooltip}
              onHide={hideTooltip}
            />
          ))}
          {activeFilters.has(OUTROS.code) && (
            <LegendItem cls={OUTROS} onShow={showTooltip} onHide={hideTooltip} />
          )}
          {activeFilters.size === 0 && (
            <div className="legend-empty">Nenhuma classe selecionada.</div>
          )}
        </div>
      </div>

      {tooltip && <LegendTooltip state={tooltip} />}
    </div>
  );
}

interface LegendItemProps {
  cls: SoilClass;
  onShow: (cls: SoilClass, rect: DOMRect) => void;
  onHide: () => void;
}

function LegendItem({ cls, onShow, onHide }: LegendItemProps) {
  const handleEnter = (e: MouseEvent<HTMLDivElement>) => {
    onShow(cls, e.currentTarget.getBoundingClientRect());
  };
  const handleFocus = (e: FocusEvent<HTMLDivElement>) => {
    onShow(cls, e.currentTarget.getBoundingClientRect());
  };

  return (
    <div
      className="legend-item"
      tabIndex={0}
      onMouseEnter={handleEnter}
      onMouseLeave={onHide}
      onFocus={handleFocus}
      onBlur={onHide}
      aria-describedby={`legend-tooltip-${cls.code}`}
    >
      <span className="dot" style={{ backgroundColor: cls.color }} />
      <span className="legend-name">{cls.label}</span>
    </div>
  );
}

function LegendTooltip({ state }: { state: LegendTooltipState }) {
  const { cls, anchorRight, anchorTop } = state;
  return (
    <div
      className="legend-tooltip"
      role="tooltip"
      id={`legend-tooltip-${cls.code}`}
      style={{ right: window.innerWidth - anchorRight, top: anchorTop }}
    >
      <div className="legend-tooltip-title">
        <span className="legend-tooltip-code">{cls.code}</span>
        {cls.label}
      </div>
      <div className="legend-tooltip-body">{cls.description}</div>
    </div>
  );
}

function SoilPopupContent({ properties }: { properties: SoilProperties }) {
  const cls = getSoilClass(properties.soilClass);
  return (
    <div className="soil-popup">
      <div className="popup-header">
        <span className="type-badge" style={{ backgroundColor: cls.color }}>
          {cls.code === OUTROS.code ? "?" : cls.code}
        </span>
        {cls.label}
      </div>
      {properties.DSC_COMPON && (
        <div className="popup-row">
          <span>Componente</span>
          <span>{properties.DSC_COMPON}</span>
        </div>
      )}
      {properties.DSC_COMPO1 && (
        <div className="popup-row">
          <span>Componente 2</span>
          <span>{properties.DSC_COMPO1}</span>
        </div>
      )}
      {properties.DSC_COMPO2 && (
        <div className="popup-row">
          <span>Componente 3</span>
          <span>{properties.DSC_COMPO2}</span>
        </div>
      )}
      {properties.DSC_TEXTUR && (
        <div className="popup-row">
          <span>Textura</span>
          <span>{properties.DSC_TEXTUR}</span>
        </div>
      )}
      {properties.COD_LEGEND && (
        <div className="popup-row">
          <span>Código</span>
          <span>{properties.COD_LEGEND}</span>
        </div>
      )}
    </div>
  );
}

function ProjectPopupContent({ project }: { project: ActiveProject }) {
  return (
    <div className="project-popup">
      {project.urlPhoto && (
        <img
          className="project-popup-photo"
          src={project.urlPhoto}
          alt={project.title}
          loading="lazy"
        />
      )}
      <div className="project-popup-body">
        <div className="project-popup-title">{project.title}</div>
        <p className="project-popup-description">{project.description}</p>
        <div className="project-popup-meta">
          {project.lat.toFixed(4)}, {project.lng.toFixed(4)}
        </div>
        {project.urlProjeto && (
          <a
            className="project-popup-link"
            href={project.urlProjeto}
            target="_blank"
            rel="noopener noreferrer"
          >
            Ver projeto →
          </a>
        )}
      </div>
    </div>
  );
}
